\displaystyle{\begin{aligned}
  \frac{{\frac{1}{r-1}-\frac{2}{r+1}}}{{2-\frac{1}{r+1}}} \amp = \frac{({\frac{1}{r-1}-\frac{2}{r+1}})\cdot{\left(r-1\right)\mathopen{}\left(r+1\right)}}{({2-\frac{1}{r+1}})\cdot{\left(r-1\right)\mathopen{}\left(r+1\right)}} \\
    \amp = \frac{{\frac{1}{r-1}\mathopen{}\left(r-1\right)\mathopen{}\left(r+1\right)-\frac{2}{r+1}\mathopen{}\left(r-1\right)\mathopen{}\left(r+1\right)}}{{2\mathopen{}\left(r-1\right)\mathopen{}\left(r+1\right)-\frac{1}{r+1}\mathopen{}\left(r-1\right)\mathopen{}\left(r+1\right)}} \\
    \amp = \frac{{r+1-2\mathopen{}\left(r-1\right)}}{{2\mathopen{}\left(r^{2}-1\right)-\left(r-1\right)}}, r \ne -1 \text{ and }  r \ne 1 \\
    \amp = \frac{{r+1-2r+2}}{{2r^{2}-2-r+1}}, r \ne -1 \text{ and }  r \ne 1 \\
    \amp = \frac{{-r+3}}{{2r^{2}-r-1}}, r \ne -1 \text{ and }  r \ne 1 \\
    \amp = {-\frac{r-3}{\left(2r+1\right)\mathopen{}\left(r-1\right)}, r\ne -1}
\end{aligned}
    }
